/**
 * Integration: PLUGIN_DATA → session-tracker → real filesystem
 * CC 2.1.78 Issue #1107
 *
 * Validates the full flow: setting CLAUDE_PLUGIN_DATA → getSessionStorageDir()
 * returns correct path → trackEvent writes events.jsonl under PLUGIN_DATA tree.
 *
 * Uses REAL filesystem (os.tmpdir), no fs mocks.
 */

import { describe, it, expect, beforeEach, afterAll, vi } from 'vitest';
import { mkdtempSync, existsSync, readFileSync, rmSync } from 'node:fs';
import path from 'node:path';
import os from 'node:os';

// We need to mock only user-identity (deterministic identity) and logHook (suppress output)
// Everything else is real: paths.ts, session-tracker.ts, analytics-buffer.ts, atomic-write.ts, fs
vi.mock('../../lib/user-identity.js', () => ({
  getIdentityContext: vi.fn(() => ({
    session_id: 'integ-session-001',
    user_id: 'integ@test.com',
    anonymous_id: 'anon-integ-001',
    team_id: undefined,
    machine_id: 'integ-machine',
    identity_source: 'config',
    timestamp: '2026-03-18T10:00:00.000Z',
  })),
}));

vi.mock('../../lib/common.js', async () => {
  const actual = await vi.importActual<typeof import('../../lib/common.js')>('../../lib/common.js');
  return {
    ...actual,
    logHook: vi.fn(),
    // getProjectDir and getSessionId use real env var reads
  };
});

import { getSessionStorageDir, getAnalyticsStorageDir, getPluginDataDir } from '../../lib/paths.js';
import { trackEvent, resetEventCounter, flushEventCounter } from '../../lib/session-tracker.js';
import { flush as flushAnalytics } from '../../lib/analytics-buffer.js';

// =============================================================================
// Real temp directory setup
// =============================================================================

let tmpDir: string;
let pluginDataDir: string;
const savedEnv: Record<string, string | undefined> = {};

function saveEnv(...keys: string[]): void {
  for (const key of keys) {
    savedEnv[key] = process.env[key];
  }
}

function restoreEnv(): void {
  for (const [key, value] of Object.entries(savedEnv)) {
    if (value === undefined) {
      delete process.env[key];
    } else {
      process.env[key] = value;
    }
  }
}

describe('PLUGIN_DATA → session-tracker integration (real filesystem)', () => {
  beforeEach(() => {
    // Create a fresh temp dir per test
    tmpDir = mkdtempSync(path.join(os.tmpdir(), 'ork-integ-'));
    pluginDataDir = path.join(tmpDir, 'plugin-data');

    saveEnv('CLAUDE_PLUGIN_DATA', 'CLAUDE_PROJECT_DIR', 'CLAUDE_SESSION_ID');

    process.env.CLAUDE_PLUGIN_DATA = pluginDataDir;
    process.env.CLAUDE_PROJECT_DIR = path.join(tmpDir, 'project');
    process.env.CLAUDE_SESSION_ID = 'integ-session-001';

    resetEventCounter();
  });

  afterAll(() => {
    restoreEnv();
    // Cleanup all temp dirs
    try {
      if (tmpDir && existsSync(tmpDir)) {
        rmSync(tmpDir, { recursive: true, force: true });
      }
    } catch {
      // Best effort cleanup
    }
  });

  // ===========================================================================
  // Path resolution
  // ===========================================================================
  describe('path resolution with PLUGIN_DATA', () => {
    it('getPluginDataDir returns the CLAUDE_PLUGIN_DATA value', () => {
      expect(getPluginDataDir()).toBe(pluginDataDir);
    });

    it('getSessionStorageDir returns PLUGIN_DATA/sessions', () => {
      const dir = getSessionStorageDir();
      expect(dir).toBe(path.join(pluginDataDir, 'sessions'));
    });

    it('getAnalyticsStorageDir returns PLUGIN_DATA/analytics', () => {
      const dir = getAnalyticsStorageDir();
      expect(dir).toBe(path.join(pluginDataDir, 'analytics'));
    });

    it('session and analytics dirs are siblings under PLUGIN_DATA', () => {
      const sessionDir = getSessionStorageDir();
      const analyticsDir = getAnalyticsStorageDir();
      expect(path.dirname(sessionDir)).toBe(path.dirname(analyticsDir));
      expect(path.dirname(sessionDir)).toBe(pluginDataDir);
    });
  });

  // ===========================================================================
  // Real file creation via trackEvent
  // ===========================================================================
  describe('trackEvent writes to PLUGIN_DATA directory tree', () => {
    it('creates session directory under PLUGIN_DATA', () => {
      trackEvent('skill_invoked', 'test-skill', { success: true });
      flushAnalytics();

      const sessionDir = path.join(pluginDataDir, 'sessions', 'integ-session-001');
      expect(existsSync(sessionDir)).toBe(true);
    });

    it('writes events.jsonl under PLUGIN_DATA/sessions/{session_id}', () => {
      trackEvent('skill_invoked', 'test-skill', { success: true });
      flushAnalytics();

      const eventsPath = path.join(pluginDataDir, 'sessions', 'integ-session-001', 'events.jsonl');
      expect(existsSync(eventsPath)).toBe(true);
    });

    it('events.jsonl contains valid JSON lines', () => {
      trackEvent('skill_invoked', 'first-skill', { success: true });
      trackEvent('agent_spawned', 'test-agent', { success: true });
      flushAnalytics();

      const eventsPath = path.join(pluginDataDir, 'sessions', 'integ-session-001', 'events.jsonl');
      const content = readFileSync(eventsPath, 'utf8');
      const lines = content.trim().split('\n').filter(Boolean);

      expect(lines.length).toBe(2);
      const event1 = JSON.parse(lines[0]);
      const event2 = JSON.parse(lines[1]);
      expect(event1.event_type).toBe('skill_invoked');
      expect(event2.event_type).toBe('agent_spawned');
    });

    it('events do NOT land in legacy .claude/memory path', () => {
      trackEvent('tool_used', 'Read', { success: true });
      flushAnalytics();

      const legacyDir = path.join(process.env.CLAUDE_PROJECT_DIR!, '.claude', 'memory', 'sessions');
      expect(existsSync(legacyDir)).toBe(false);
    });
  });

  // ===========================================================================
  // Counter persistence under PLUGIN_DATA
  // ===========================================================================
  describe('event counter persists under PLUGIN_DATA', () => {
    it('flushEventCounter writes counter.json under PLUGIN_DATA session dir', () => {
      trackEvent('skill_invoked', 'counter-test', { success: true });
      flushEventCounter();

      const counterPath = path.join(pluginDataDir, 'sessions', 'integ-session-001', 'counter.json');
      expect(existsSync(counterPath)).toBe(true);

      const data = JSON.parse(readFileSync(counterPath, 'utf8'));
      expect(data.counter).toBeGreaterThan(0);
      expect(data.updated_at).toBeDefined();
    });
  });

  // ===========================================================================
  // Fallback when PLUGIN_DATA is absent
  // ===========================================================================
  describe('legacy fallback when PLUGIN_DATA is absent', () => {
    it('getSessionStorageDir falls back to project-local path', () => {
      delete process.env.CLAUDE_PLUGIN_DATA;
      const dir = getSessionStorageDir();
      expect(dir).toContain('.claude');
      expect(dir).toContain('memory');
      expect(dir).toContain('sessions');
      expect(dir).not.toContain('plugin-data');
    });

    it('getAnalyticsStorageDir falls back to project-local path', () => {
      delete process.env.CLAUDE_PLUGIN_DATA;
      const dir = getAnalyticsStorageDir();
      expect(dir).toContain('.claude');
      expect(dir).toContain('memory');
      expect(dir).toContain('analytics');
    });
  });
});
